#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    // Consequence of std::vector<std::vector<>>: each row is a separate
    // contiguous block.  Access patterns are already relatively cache
    // friendly.  We simply expose the raw data pointers for the inner
    // loops and add OpenMP parallelism.

    /* Parallelise over the outer two loops.  The innermost loop
       (over k) has data dependencies that make it difficult to
       parallelise directly; instead we compute a partial sum per
       thread and accumulate it before the final scaling by alpha.   */
    #pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            // Vectorised accumulation over k (k > i)
            for (int k = i + 1; k < m; ++k) {
                sum += A[k][i] * B[k][j];
            }
            B[i][j] += sum;          // add the contribution
            B[i][j] *= alpha;        // scale by alpha
        }
    }
}
