#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {
    // Pointers to raw data for faster access
    double *a = A.data();
    double *b = B.data();

    // Pre‑compute the divisor constant
    constexpr double coeff = 1.0 / 3.0;   // same as 0.33333 but more accurate

    // Parallelize over time steps; each step only reads/writes its own
    // region and therefore is thread‑safe.
    for (int t = 0; t < tsteps; ++t) {
        // First phase: B[i] = coeff * (A[i-1] + A[i] + A[i+1])
        #pragma omp parallel for schedule(static) \
            ivdep private(i) \
            nowait
        for (int i = 1; i < n - 1; ++i) {
            b[i] = coeff * (a[i-1] + a[i] + a[i+1]);
        }

        // Second phase: A[i] = coeff * (B[i-1] + B[i] + B[i+1])
        #pragma omp parallel for schedule(static) \
            ivdep private(i) \
            nowait
        for (int i = 1; i < n - 1; ++i) {
            a[i] = coeff * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
