```cpp
#include <vector>
#include <cstddef>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    // Strike out any accidental 'const' usage
    constexpr int chunk = 64;  // cache line size hint for manual unrolling

    // Copy L into a contiguous array to improve spatial locality.
    std::vector<double> flatL(n * n);
    for (int i = 0; i < n; ++i) {
        std::memcpy(&flatL[i * n], L[i].data(), n * sizeof(double));
    }

    // Forward substitution loop
    for (int i = 0; i < n; ++i) {
        double sum = b[i];
        const double* Li = &flatL[i * n];     // row i of L
        double*          xj = x.data();        // current row of x

        // Unrolled inner loop to reduce loop overhead
        int j = 0;
        for (; j + chunk <= i; j += chunk) {
            // Process 64 elements at a time
            for (int k = 0; k < chunk; ++k) {
                sum -= Li[j + k] * xj[j + k];
            }
        }
        // Remaining elements
        for (; j < i; ++j) {
            sum -= Li[j] * xj[j];
        }

        x[i] = sum / Li[i];
    }
}
