#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* 1. Flatten the 2D input matrices to 1D buffers to reduce
       pointer indirection and improve cache locality.  This is
       a one‑time cost per kernel call and costs O(n²) which is
       negligible compared to the O(n²) iteration below.              */
    std::vector<double> a(n * n);
    std::vector<double> b(n * n);

    for (int i = 0; i < n; ++i) {
        const double* Aptr = A[i].data();
        const double* Bptr = B[i].data();
        double*    aRow = &a[i * n];
        double*    bRow = &b[i * n];
        for (int j = 0; j < n; ++j) {
            aRow[j] = Aptr[j];
            bRow[j] = Bptr[j];
        }
    }

    /* 2. Use OpenMP for parallelism across the outer loop (rows). */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double buf_tmp = 0.0;
        double buf_y   = 0.0;
        const double* aRow = &a[i * n];
        const double* bRow = &b[i * n];
        const double* xRow = &x[0];
        for (int j = 0; j < n; ++j) {
            buf_tmp += aRow[j] * xRow[j];
            buf_y   += bRow[j] * xRow[j];
        }
        tmp[i] = buf_tmp;
        y[i]   = alpha * buf_tmp + beta * buf_y;
    }
}
