```cpp
// Optimised GEMM – preserves the original interface and semantics
#include <vector>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // Parallelise over the outermost loop (rows of C/A)
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        // Pointers to the current rows for faster indexing
        double*        aRow = A[i].data();
        std::vector<double> &cRow = C[i];
        double*        cPtr = cRow.data();

        // Scale the row by beta once
        for (int j = 0; j < nj; ++j) cPtr[j] *= beta;

        // Compute the dot products
        for (int k = 0; k < nk; ++k) {
            double aik = aRow[k] * alpha;            // reuse the product
            double* bRow = B[k].data();              // pointer to B's row

            // Unroll the inner loop in blocks of 4 for better pipeline use
            int j = 0;
            for (; j <= nj - 4; j += 4) {
                cPtr[j]   += aik * bRow[j];
                cPtr[j+1] += aik * bRow[j+1];
                cPtr[j+2] += aik * bRow[j+2];
                cPtr[j+3] += aik * bRow[j+3];
            }
            for (; j < nj; ++j) {
                cPtr[j] += aik * bRow[j];
            }
        }
    }
}
