#include <vector>
#include <algorithm>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    /* Local helpers to get contiguous pointers */
    std::vector<double*> Cptr(n), Aptr(m), Bptr(m);
    for (int i = 0; i < n; ++i) Cptr[i] = C[i].data();
    for (int k = 0; k < m; ++k) Aptr[k] = A[k].data();   // A is NxM -> transpose
    for (int k = 0; k < m; ++k) Bptr[k] = B[k].data();

    /* Main loop – parallelised over the i‑dimension (outer row) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double *Ci = Cptr[i];
        double *Ai = Aptr[i];            // A[i][k]
        /* Scale lower‑triangular part of C by beta */
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= beta;
        }

        /* Accumulate the rank‑2 update */
        for (int k = 0; k < m; ++k) {
            double *Ak = Aptr[k];          // A[?][k] – column k of A
            double *Bk = Bptr[k];          // B[?][k] – column k of B
            double aik = alpha * Ai[k];
            double aik2 = alpha * Ak[i];

            for (int j = 0; j <= i; ++j) {
                Ci[j] += Ak[j] * aik + Bk[j] * aik2;
            }
        }
    }
}
