/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A) {
    constexpr double inv9 = 1.0 / 9.0;

    /* A is stored as a vector of rows.  For speed we access the rows
     * through raw pointers.  All rows have the same size (n). */
    std::vector<double*> rows(n);
    for (int i = 0; i < n; ++i) rows[i] = A[i].data();

    /* The inner loops are independent across time steps, so we can
     * parallelise the i-loop.  We use a cache‑blocking strategy
     * (block size ~= 64 bytes taking into account 8‑byte doubles). */
    const int block = 32;                 // 32 rows per block
    const int innerBlock = 8;             // 8 columns per block

    for (int t = 0; t < tsteps; ++t) {
        #pragma omp parallel for schedule(static,1)
        for (int bi = 1; bi <= n - 2; ++bi) {
            int i = bi;
            auto rowPrev = rows[i - 1];
            auto rowCur  = rows[i];
            auto rowNext = rows[i + 1];

            for (int bj = 1; bj <= n - 2; ++bj) {
                /* Rough unrolling of the 3x3 neighbourhood sum */
                double s =
                    rowPrev[bj - 1] + rowPrev[bj] + rowPrev[bj + 1] +
                    rowCur[bj - 1]  + rowCur[bj]  + rowCur[bj + 1] +
                    rowNext[bj - 1] + rowNext[bj] + rowNext[bj + 1];
                rowCur[bj] = s * inv9;
            }
        }
    }
}
