/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    // The outer loop cannot be parallelised because each row depends on all
    // previous rows.  Instead, the part of the row that is independent of any
    // later computations is parallelised.
    for (int i = 0; i < n; ++i) {
        // ---- Upper‑triangle part (j < i) ---------------------------------
        for (int j = 0; j < i; ++j) {
            double* row_i = A[i].data();
            double* row_j = A[j].data();
            double* row_k;
            // Compute the dot‑product for the column j
            for (int k = 0; k < j; ++k) {
                row_k = A[k].data();
                row_i[j] -= row_i[k] * row_k[j];
            }
            // Scale by the pivot element
            row_i[j] /= row_j[j];
        }

        // ---- Lower‑triangle part (j >= i) ---------------------------------
        // This part has no dependencies between different j's and can be
        // parallelised safely.
        #pragma omp parallel for schedule(static)
        for (int j = i; j < n; ++j) {
            double* row_i = A[i].data();
            double* row_j = A[j].data();
            double* row_k;
            for (int k = 0; k < i; ++k) {
                row_k   = A[k].data();
                row_i[j] -= row_i[k] * row_k[j];
            }
        }
    }
}
