/* Main computational kernel. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    /* Each *row* of C is independent => safe to parallelise on i
       (i=0..n-1). */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* Ci = C[i].data();          // fast pointer to row i of C
        const std::vector<double>& Ai = A[i];

        /* Scale the lower‐triangular part of the row (j ≤ i). */
        for (int j = 0; j <= i; ++j)
            Ci[j] *= beta;

        /* Accumulate contributions from A[i][k] * A[j][k]. */
        for (int k = 0; k < m; ++k) {
            const double aik = Ai[k];
            /* We can reuse the pointer to the j‑th row of A each time */
            for (int j = 0; j <= i; ++j)
                Ci[j] += alpha * aik * A[j][k];
        }
    }
}
