#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
  /* 1st stage:  tmp = alpha * A * B
     Parallelise the outermost loop.  Each thread works on a disjoint
     set of rows of tmp.  Because the rows are independent we can use
     a simple schedule without any synchronization cost.  */
#pragma omp parallel for schedule(static)
  for (int i = 0; i < ni; ++i) {
    double* const tmp_row = tmp[i].data();
    const double* const A_row = A[i].data();

    for (int j = 0; j < nj; ++j) {
      double sum = 0.0;
      const double* B_col = &B[0][j];        // first element of column j
      /* inner product of A_row[0..nk-1] and column j of B */
      for (int k = 0; k < nk; ++k) {
        sum += A_row[k] * B_col[k * nj];     // B[k][j] -> B[k*nj + j]
      }
      tmp_row[j] = alpha * sum;
    }
  }

  /* 2nd stage:  D = beta * D + tmp * C
     Parallelise over the rows of D.  */
#pragma omp parallel for schedule(static)
  for (int i = 0; i < ni; ++i) {
    double* const D_row = D[i].data();
    const double* const tmp_row = tmp[i].data();

    for (int j = 0; j < nl; ++j) {
      double sum = D_row[j] * beta;          // initial beta scaling

      for (int k = 0; k < nj; ++k) {
        sum += tmp_row[k] * C[k][j];
      }
      D_row[j] = sum;
    }
  }
}
