#include <vector>
#include <algorithm>
#include <omp.h>

/// Optimised Floyd‑Warshall on a 2‑D integer matrix.
///
/// The implementation keeps the public interface unchanged but
/// accelerates the inner loops by:
///   * flattening the two‑dimensional lookups to raw pointers,  
///   * hoisting invariant loads out of the j‑loop,  
///   * removing the template argument from `std::min`,  
///   * and parallelising the outer `i` loop for every `k` value.
///
/// The algorithmic semantics remain identical: after the call `path[i][j]`
/// contains the shortest path distance between `i` and `j` using only
/// intermediate vertices from the set `{0,…,k}` for each iteration of `k`.
///
void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path)
{
    // For each intermediate vertex k
    for (int k = 0; k < n; ++k)
    {
        // Pre‑fetch the row corresponding to k once per k‑iteration.
        const std::vector<int>& row_k = path[k];
        const int*    ptr_k = row_k.data();

        // Parallelise the i‑loop: each thread works on a disjoint set of rows.
#pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i)
        {
            std::vector<int>&    row_i = path[i];
            int*                 ptr_i = row_i.data();
            const int            row_i_k = ptr_k[i];          // path[i][k]

            // If path[i][k] is already infinite (or a sentinel) the update
            // can be skipped; however, the benchmark uses small positive
            // values, so we keep the simple update for correctness.
            for (int j = 0; j < n; ++j)
            {
                const int new_dist = row_i_k + ptr_k[j];     // path[i][k] + path[k][j]
                if (new_dist < ptr_i[j])
                    ptr_i[j] = new_dist;
            }
        }
    }
}
