```cpp
#include <cmath>
#include <vector>
#include <numeric>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    const double eps = 0.1;
    const double inv_n   = 1.0 / n;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    // ------------------------------------------------------------------
    // 1) Compute means (parallel over columns)
    // ------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) s += data[i][j];
        mean[j] = s * inv_n;
    }

    // ------------------------------------------------------------------
    // 2) Compute standard deviations (parallel over columns)
    // ------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double ss = 0.0;
        const double mj = mean[j];
        for (int i = 0; i < n; ++i) {
            const double d = data[i][j] - mj;
            ss += d * d;
        }
        ss *= inv_n;
        double sd = std::sqrt(ss);
        // Avoid division by zero for near‑zero stddev
        stddev[j] = (sd <= eps) ? 1.0 : sd;
    }

    // ------------------------------------------------------------------
    // 3) Center and scale data (parallel over rows)
    // ------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double v = data[i][j] - mean[j];
            v *= inv_sqrt_n / stddev[j];
            data[i][j] = v;
        }
    }

    // ------------------------------------------------------------------
    // 4) Compute correlation matrix (upper triangle, then symmetric)
    // ------------------------------------------------------------------
    #pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m - 1; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k) {
                s += data[k][i] * data[k][j];
            }
            corr[i][j] = s;
            corr[j][i] = s;   // symmetric
        }
    }
    corr[m-1][m-1] = 1.0;
}
