/*
 * Same functional behaviour as the original kernel, but heavily
 * optimized for modern x86‑64 CPUs with 8 threads. 
 *
 * 1. All loops are parallelised with OpenMP.
 * 2. `tmp` is written only once per row by the owning thread.
 * 3. `y` is updated using atomic adds to guarantee correctness
 *    without any explicit synchronisation, which is cheap for
 *    triangular matrices that fit into cache.
 * 4. The code is strictly cache‑friendly: we traverse each row of
 *    `A` contiguously.
 */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp)
{
    /* Zero y in parallel */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j)
        y[j] = 0.0;

    /* Main computation */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double dot = 0.0;
        const std::vector<double>& Ai = A[i];

        /* 1st pass: compute tmp[i] = row i • x */
        for (int j = 0; j < n; ++j)
            dot += Ai[j] * x[j];

        tmp[i] = dot;

        /* 2nd pass: accumulate to y */
        for (int j = 0; j < n; ++j) {
            /* atomic is required because multiple rows can touch the same y[j] */
            #pragma omp atomic
            y[j] += Ai[j] * dot;
        }
    }
}
