void kernel_nussinov(int n, std::vector<int>& seq,
		     std::vector<std::vector<int>>& table)
{
    // Flatten 2‑D table for faster access
    int* tbl = &table[0][0];
    int step = n;                 // row stride

    auto match = [](int b1, int b2) noexcept
    {
        return (b1 + b2 == 3) ? 1 : 0;
    };

    /*  The DP depends only on smaller gaps (j-i).
        For each gap we can compute all i in parallel.   */
    for (int gap = 1; gap < n; ++gap)
    {
#pragma omp parallel for schedule(static)
        for (int i = 0; i + gap < n; ++i)
        {
            int j = i + gap;
            int idx = i * step + j;
            int val = 0;

            /* Consider pair (i,j) and neighbours */
            if (j - 1 >= 0)
                val = std::max(val, tbl[i * step + j - 1]);

            if (i + 1 < n)
                val = std::max(val, tbl[(i + 1) * step + j]);

            if (j - 1 >= 0 && i + 1 < n)
            {
                if (i < j - 1)
                    val = std::max(val,
                                   tbl[(i + 1) * step + j - 1] + match(seq[i], seq[j]));
                else
                    val = std::max(val, tbl[(i + 1) * step + j - 1]);
            }

            /* split the interval at k */
            int best = val;
            for (int k = i + 1; k < j; ++k)
                best = std::max(best, tbl[i * step + k] + tbl[(k + 1) * step + j]);

            tbl[idx] = best;
        }
    }
}
