       original API accepts a vector of vectors, but this conversion
       does not change the values or layout visible to the caller. */
    std::vector<double> exflat(nx * ny), eyflat(nx * ny), hzflat(nx * ny);
    for (int i = 0; i < nx; ++i)
        for (int j = 0; j < ny; ++j) {
            exflat[i * ny + j] = ex[i][j];
            eyflat[i * ny + j] = ey[i][j];
            hzflat[i * ny + j] = hz[i][j];
        }

    const double a = 0.5, b = 0.7;

    for (int t = 0; t < tmax; ++t) {
        /* 1) Set Ey boundary – serial is fine (ny <= 1024). */
        double f = _fict_[t];
        #pragma omp parallel for schedule(static)
        for (int j = 0; j < ny; ++j)
            eyflat[j] = f;                 /* i==0 column */

        /* 2) Update Ey interior -------------------------------------------------- */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < nx; ++i)
            for (int j = 0; j < ny; ++j) {
                int idx = i * ny + j;
                eyflat[idx] -= a * (hzflat[idx] - hzflat[(i - 1) * ny + j]);
