        /* 3) Update Ex interior -------------------------------------------------- */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx; ++i)
            for (int j = 1; j < ny; ++j) {
                int idx = i * ny + j;
                exflat[idx] -= a * (hzflat[idx] - hzflat[i * ny + j - 1]);
            }

        /* 4) Update Hz interior --------------------------------------------------- */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx1; ++i)
            for (int j = 0; j < ny1; ++j) {
                int idx = i * ny + j;
                int idx_next_j = i * ny + j + 1;
