/* Main computational kernel.
   The whole function will be timed, including the call and return.
   All matrix data are stored as std::vector<std::vector<double>> with
   each inner vector being a contiguous row of doubles. */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
                std::vector<std::vector<double>>& E,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& F,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D,
                std::vector<std::vector<double>>& G)
{
    /* 1. Compute E = A * B  (ni × nk) * (nk × nj) -> (ni × nj)  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* const restrict e_row = E[i].data();
        const std::vector<double>& a_row = A[i];
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nk; ++k) {
                sum += a_row[k] * B[k][j];
            }
            e_row[j] = sum;
        }
    }

    /* 2. Compute F = C * D  (nj × nm) * (nm × nl) -> (nj × nl)  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < nj; ++i) {
        double* const restrict f_row = F[i].data();
        const std::vector<double>& c_row = C[i];
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nm; ++k) {
                sum += c_row[k] * D[k][j];
            }
            f_row[j] = sum;
        }
    }

    /* 3. Compute G = E * F  (ni × nj) * (nj × nl) -> (ni × nl)  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* const restrict g_row = G[i].data();
        const std::vector<double>& e_row = E[i];
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nj; ++k) {
                sum += e_row[k] * F[k][j];
            }
            g_row[j] = sum;
        }
    }
}
