 *
 * ====================================================================== */

static inline double dot_product(const double* a, const double* b, std::size_t m)
{
    double sum = 0.0;
    std::size_t i = 0;
    // Unroll for 8 multiplications at a time
    for (; i + 7 < m; i += 8)
        sum += a[i]*b[i] + a[i+1]*b[i+1] + a[i+2]*b[i+2] + a[i+3]*b[i+3]
            + a[i+4]*b[i+4] + a[i+5]*b[i+5] + a[i+6]*b[i+6] + a[i+7]*b[i+7];
    for (; i < m; ++i)
        sum += a[i]*b[i];
    return sum;
}

void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    /* ------------------------------------------------------------------ */
    /* 1. Flatten the input matrix A into a 1‑D array to ensure
     *    contiguous memory layout.  The output matrices Q and R are
     *    already in row‑major form by the caller.  We keep them as
     *    nested vectors but index them via a helper function.          */
    /* ------------------------------------------------------------------ */
    std::vector<double> flat_A(m * n);
    for (int i = 0; i < m; ++i)
        std::copy(A[i].begin(), A[i].end(), flat_A.begin() + i*n);

    /* Helper to access element (row, col) in a row‑major flattened vec */
    auto idx = [n](int i, int j) noexcept -> std::size_t { return i*n + j; };

    /* ------------------------------------------------------------------ */
    /* 2. The main Modified Gram‑Schmidt loop.                              */
    /* ------------------------------------------------------------------ */
    for (int k = 0; k < n; ++k) {
        /* 2a. Compute norm of the k‑th current column of A */
        const double* col_k = &flat_A[idx(0, k)];
        double nrm = 0.0;
        #pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i)
            nrm += col_k[i] * col_k[i];
        double rk = std::sqrt(nrm);
        R[k][k] = rk;

        /* 2b. Normalise the column and store into Q */
        const double inv_rk = 1.0 / rk;
        for (int i = 0; i < m; ++i)
            Q[i][k] = col_k[i] * inv_rk;

        /* 2c. Orthogonalise subsequent columns in parallel */
        #pragma omp parallel for schedule(static)
        for (int j = k + 1; j < n; ++j) {
            const double* col_j = &flat_A[idx(0, j)];
            double rkj = dot_product(Q[i], col_j, m);           // Q(:,k)·col_j
            R[k][j] = rkj;
            double coef = rkj;
            for (int i = 0; i < m; ++i)
                flat_A[idx(i, j)] = col_j[i] - Q[i][k] * coef;
        }
    }

    /* ------------------------------------------------------------------ */
    /* 3. Copy results from the temporary flat_A back to the supplied A.  */
    /* ------------------------------------------------------------------ */
    for (int i = 0; i < m; ++i)
        std::copy(flat_A.begin() + i*n, flat_A.begin() + (i+1)*n,
                  A[i].begin());
}
