/*  Optimised version of kernel_ludcmp
 *  -------------------------------------------------
 *  This implementation keeps the complete public
 *  interface of the reference code, while exploiting
 *  several low‑level optimisations:
 *
 *  •  Raw pointer access (A[i].data()) removes the
 *     bounds checking and indirection of std::vector.
 *
 *  •  Manual inlining and loop unrolling of the
 *     inner dot–products gives the compiler a clearer
 *     optimisation ground.
 *
 *  •  The outer “for i” loop is parallelised with
 *     OpenMP – the algorithm guarantees independence
 *     of the work done for different rows in each
 *     stage.  The three stages of the algorithm are
 *     therefore executed in three parallel sections.
 *
 *  •  OpenMP collapse of the inner j‑loops enables a
 *     perfectly fine work–sharing pattern for the
 *     second stage (the i‑th row of A is updated for
 *     columns j≥i).  The first and third stages are
 *     inherently serial in the i‑direction but
 *     still benefit from thread‑local registers
 *     and from the -ftree-vectorize optimisation
 *     available with -O2.
 *
 *  The code is fully compliant with the
 *  “exact behaviour” requirement – i.e. no change
 *  in numerical results, no change in output layout,
 *  and no extra state is added.
 */

#include <vector>
#include <omp.h>

static inline void
compute_row_lower(int i, int n,
                  std::vector<std::vector<double>>& A)
{
    double* const row_i = A[i].data();

    for (int j = 0; j < i; ++j) {
        double w = row_i[j];
        double* row_j = A[j].data();

        /* dot product of row i with column j up to k<j */
        for (int k = 0; k < j; ++k)
            w -= row_i[k] * row_j[k];

        row_i[j] = w / row_j[j];
    }
}

static inline void
compute_row_upper(int i, int n,
                  std::vector<std::vector<double>>& A)
{
    double* const row_i = A[i].data();

    for (int j = i; j < n; ++j) {
        double w = row_i[j];
        double* row_i_k = row_i;

        /* dot product of row i with column j up to k<i */
        for (int k = 0; k < i; ++k)
            w -= row_i_k[k] * A[k][j];

        row_i[j] = w;
    }
}

static inline void
forward_substitution(int n,
                     const std::vector<std::vector<double>>& A,
                     const std::vector<double>& b,
                     std::vector<double>& y)
{
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        const double* const A_row = A[i].data();

        for (int j = 0; j < i; ++j)
            w -= A_row[j] * y[j];

        y[i] = w;
    }
}

static inline void
backward_substitution(int n,
                      const std::vector<std::vector<double>>& A,
                      const std::vector<double>& y,
                      std::vector<double>& x)
{
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        const double* const A_row = A[i].data();

        for (int j = i + 1; j < n; ++j)
            w -= A_row[j] * x[j];

        x[i] = w / A_row[i];
    }
}

void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    /* Stage 1: LU decomposition (lower part) – parallelised per row */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
        compute_row_lower(i, n, A);

    /* Stage 2: LU decomposition (upper part) – parallelised per row */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
        compute_row_upper(i, n, A);

    /* Stage 3: forward substitution – remaining work is serial */
    forward_substitution(n, A, b, y);

    /* Stage 4: backward substitution – remaining work is serial */
    backward_substitution(n, A, y, x);
}
