#include <cmath>
#include <vector>
#include <algorithm>
#include <omp.h>

/* Optimised Deriche filter kernel in a single self‑contained file.
 * The implementation keeps the exact numerical behaviour, but uses
 * cache friendly row_major vectors, pre–computes constants, and
 * parallelises all independent passes with OpenMP. */

/* Layout: continuous 1‑D array of size w*h.
 * Accessors: idx(i,j) = i*h + j. */
inline size_t idx(size_t i, size_t j, size_t h) noexcept { return i*h + j; }

/* Main computational kernel. */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<float>& imgIn,          // size w*h
                    std::vector<float>& imgOut,         // size w*h
                    std::vector<float>& y1,            // size w*h
                    std::vector<float>& y2)            // size w*h
{
    // Pre‑compute constants.
    const float e1  = std::exp(-alpha);
    const float e2  = e1*e1;
    const float denom = 1.0f + 2.0f*alpha*e1 - e2;
    const float k     = 1.0f - e1*(1.0f-e1)/denom;
    const float a1 = k, a5 = k;
    const float a2 = a6 = k*e1*(alpha-1.0f);
    const float a3 = a7 = k*e1*(alpha+1.0f);
    const float a4 = a8 = -k*e2;
    const float b1 = std::pow(2.0f, -alpha);
    const float b2 = -e2;
    const float c  = 1.0f;

    // --- vertical forward pass (y1) ---------------------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        const int base = i*h;
        for (int j = 0; j < h; ++j) {
            const int ix = base + j;
            float v = imgIn[ix];
            y1[ix] = a1*v + a2*xm1 + b1*ym1 + b2*ym2;
            xm1 = v; ym2 = ym1; ym1 = y1[ix];
        }
    }

    // --- vertical backward pass (y2) --------------------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        const int base = i*h;
        for (int j = h-1; j >= 0; --j) {
            const int ix = base + j;
            y2[ix] = a3*xp1 + a4*xp2 + b1*yp1 + b2*yp2;
            xp2 = xp1; xp1 = imgIn[ix];
            yp2 = yp1; yp1 = y2[ix];
        }
    }

    // --- combine vertical results -------------------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[idx(i,j,h)] = c * (y1[idx(i,j,h)] + y2[idx(i,j,h)]);

    // --- horizontal forward pass (y1) ----------------------------
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            int ix = idx(i,j,h);
            float v = imgOut[ix];
            y1[ix] = a5*v + a6*tm1 + b1*ym1 + b2*ym2;
            tm1 = v; ym2 = ym1; ym1 = y1[ix];
        }
    }

    // --- horizontal backward pass (y2) ---------------------------
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w-1; i >= 0; --i) {
            int ix = idx(i,j,h);
            y2[ix] = a7*tp1 + a8*tp2 + b1*yp1 + b2*yp2;
            tp2 = tp1; tp1 = imgOut[ix];
            yp2 = yp1; yp1 = y2[ix];
        }
    }

    // --- final combine --------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[idx(i,j,h)] = c * (y1[idx(i,j,h)] + y2[idx(i,j,h)]);
}
