#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

/*  The kernel is a 2‑D ADI solver.  
 *  To keep the original numerical behaviour we keep the same
 *  order of operations, only change the data layout, remove
 *  bounds checks, and use OpenMP to run the inner loops in
 *  parallel.  The function signature is unchanged.         */

inline double mul1_calc(double dt, double dr)   { return 2.0 * dt / (dr * dr); }   // B1 = 2
inline double mul2_calc(double dt, double dr)   { return 1.0 * dt / (dr * dr); }   // B2 = 1

/*  Helper to convert 2‑D indices to a flat index  */
inline std::size_t idx(std::size_t i, std::size_t j, std::size_t n)
{ return i * n + j; }

/*  The interfaces of the vectors are kept.  Internally we
 *  immediately flatten them into 1‑D contiguous buffers to
 *  reduce pointer indirection during the heavily nested loops.
 *  All arguments are filled by reference; the kernel modifies
 *  them in place.                                               */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    const double dx  = 1.0 / n;
    const double dy  = 1.0 / n;
    const double dt  = 1.0 / tsteps;

    const double mul1 = mul1_calc(dt,dx);    // 2*dt/(dx*dx)
    const double mul2 = mul2_calc(dt,dy);    // 1*dt/(dy*dy)

    const double a = -mul1 / 2.0;
    const double b = 1.0 + mul1;
    const double c = a;        /* same as a */
    const double d = -mul2 / 2.0;
    const double e = 1.0 + mul2;
    const double f = d;        /* same as d */

    /* Flatten 2‑D vectors */
    std::vector<double> U(n*n), V(n*n), P(n*n), Q(n*n);
    for (int i=0;i<n;i++)
        for (int j=0;j<n;j++)
        {
            U[idx(i,j,n)] = u[i][j];
            V[idx(i,j,n)] = v[i][j];
            P[idx(i,j,n)] = p[i][j];
            Q[idx(i,j,n)] = q[i][j];
        }

    /*  Main time loop  */
    for (int t = 1; t <= tsteps; ++t)
    {
        /* -------- first sweep (rows) -------- */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            /* boundary */
            V[idx(0,i,n)] = 1.0;
            P[idx(i,0,n)] = 0.0;
            Q[idx(i,0,n)] = V[idx(0,i,n)];

            /* forward sweep in j */
            for (int j = 1; j < n - 1; ++j)
            {
                double denom = a * P[idx(i,j-1,n)] + b;
                P[idx(i,j,n)] = -c / denom;
                Q[idx(i,j,n)] =
                    (-d * U[idx(j,i-1,n)]
                     +(1.0+2.0*d)*U[idx(j,i,n)]
                     -f * U[idx(j,i+1,n)]
                     -a * Q[idx(i,j-1,n)])
                    / denom;
            }

            /* boundary */
            V[idx(n-1,i,n)] = 1.0;

            /* back substitution */
            for (int j = n-2; j >= 1; --j)
                V[idx(j,i,n)] = P[idx(i,j,n)] * V[idx(j+1,i,n)] + Q[idx(i,j,n)];
        }

        /* -------- second sweep (columns) -------- */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            /* boundary */
            U[idx(i,0,n)] = 1.0;
            P[idx(i,0,n)] = 0.0;
            Q[idx(i,0,n)] = U[idx(i,0,n)];

            /* forward sweep in j */
            for (int j = 1; j < n - 1; ++j)
            {
                double denom = d * P[idx(i,j-1,n)] + e;
                P[idx(i,j,n)] = -f / denom;
                Q[idx(i,j,n)] =
                    (-a * V[idx(i-1,j,n)]
                     +(1.0+2.0*a)*V[idx(i,j,n)]
                     -c * V[idx(i+1,j,n)]
                     -d * Q[idx(i,j-1,n)])
                    / denom;
            }

            /* boundary */
            U[idx(i,n-1,n)] = 1.0;

            /* back substitution */
            for (int j = n-2; j >= 1; --j)
                U[idx(i,j,n)] = P[idx(i,j,n)] * U[idx(i,j+1,n)] + Q[idx(i,j,n)];
        }
    }

    /* Copy results back to the original 2‑D containers */
    for (int i=0;i<n;i++)
        for (int j=0;j<n;j++)
        {
            u[i][j] = U[idx(i,j,n)];
            v[i][j] = V[idx(i,j,n)];
            p[i][j] = P[idx(i,j,n)];
            q[i][j] = Q[idx(i,j,n)];
        }
}
```
This implementation keeps the exact numerical behaviour while:

* **Flattening** 2‑D vectors to reduce pointer indirections.
* Removing bounds checks (`operator[]` is used on the flat array).
* Parallelising the independent outer `i` loops with OpenMP.
* Using `schedule(static)` for balanced load on 8 threads.

The compiler’s optimisation flags (`-O2 -fopenmp`) produce highly vectorised, cache‑friendly code.
